def f(expr):
    def precedence(op):
        if op == '*':
            return 2
        if op in ('+', '-'):
            return 1
        return 0

    def apply_op(ops, vals):
        op = ops.pop()
        b = vals.pop()
        a = vals.pop()
        if op == '+':
            vals.append(a + b)
        elif op == '-':
            vals.append(a - b)
        elif op == '*':
            vals.append(a * b)

    i, n = 0, len(expr)
    vals, ops = [], []
    while i < n:
        ch = expr[i]
        if ch.isspace():
            i += 1
            continue
        if ch.isdigit():
            num = 0
            while i < n and expr[i].isdigit():
                num = num * 10 + int(expr[i])
                i += 1
            vals.append(num)
            continue
        if ch == '(':
            ops.append(ch)
        elif ch == ')':
            while ops and ops[-1] != '(':
                apply_op(ops, vals)
            ops.pop()  # discard '('
        else:  # operator + - *
            while ops and ops[-1] != '(' and precedence(ops[-1]) >= precedence(ch):
                apply_op(ops, vals)
            ops.append(ch)
        i += 1

    while ops:
        apply_op(ops, vals)

    return vals[-1] if vals else 0
